commands.examples:
SELECT name, price,
  (SELECT AVG(price) FROM products) AS avg_price
FROM products;

SELECT * FROM products
WHERE price > (SELECT AVG(price) FROM products);

SELECT * FROM users
WHERE id IN (SELECT user_id FROM orders WHERE total > 1000000);

SELECT * FROM products
WHERE category_id NOT IN (SELECT id FROM categories WHERE is_active = FALSE);

SELECT u.username FROM users u
WHERE EXISTS (
  SELECT 1 FROM orders o WHERE o.user_id = u.id AND o.total > 500000
);

-- User tanpa order
SELECT u.username FROM users u
WHERE NOT EXISTS (
  SELECT 1 FROM orders o WHERE o.user_id = u.id
);

SELECT role, avg_orders FROM (
  SELECT u.role, AVG(order_count) AS avg_orders FROM (
    SELECT user_id, COUNT(*) AS order_count
    FROM orders GROUP BY user_id
  ) oc
  JOIN users u ON oc.user_id = u.id
  GROUP BY u.role
) summary
WHERE avg_orders > 5;

-- Produk termahal per kategori
SELECT * FROM products p
WHERE price = (
  SELECT MAX(price) FROM products
  WHERE category_id = p.category_id
);

-- Order terbaru per user
SELECT * FROM orders o
WHERE created_at = (
  SELECT MAX(created_at) FROM orders
  WHERE user_id = o.user_id
);
